export function hideAllSubmenus() {
  const verticalNavRoot = document.querySelector('mx-vertical-nav');
  const verticalNavPanelRoot = verticalNavRoot && verticalNavRoot.shadowRoot ? verticalNavRoot
    .shadowRoot.querySelector('mx-vertical-nav-panel'): undefined;

  const allVisibleSubMenus =
    Array.from(document.getElementsByTagName('mx-vertical-nav-sub-menu'))
      .filter((subMenu) => subMenu.show);
  allVisibleSubMenus.forEach((subMenu) => subMenu.show = false);

  if(verticalNavPanelRoot) {

    // Under some very specific edge case, the caret for some vertical nav items may not be updated properly,
    // so let's make sure they are all set back to the closed status.
    let verticalNavItems = Array.from(verticalNavPanelRoot.shadowRoot?.querySelectorAll('mx-vertical-nav-item'))
      .filter((navItem) => navItem.item.showSubMenu);
    verticalNavItems = verticalNavItems.map((navItem) => {
      navItem.item = { ...navItem.item, showSubMenu: false };
      return navItem;
    });
  }
}
