import { Component, Host, Prop, h, Event, EventEmitter, Watch } from '@stencil/core';
import { IMenuItem } from '@src/mx-components/layout/mx-nav/mx-nav.model';
import { IVerticalNavItem } from '@src/mx-components/layout/mx-vertical-nav/mx-vertical-nav.interface';

@Component({
  tag: 'mx-vertical-nav-sub-menu',
  styleUrl: 'mx-vertical-nav-sub-menu.css'
})
export class MxVerticalNavSubMenu {

  /** Sets whether to show or hide the sub-menu. */
  @Prop() readonly show: boolean = false;

  @Watch('show')
  onShowChange(show: boolean) {
    if (show) {
      this.registerObserver();
    } else {
      this.disconnectObserver();
    }
  }

  /** Sets the array of menu data. */
  @Prop() readonly data!: IMenuItem[];
  /** Sets the number of columns. */
  @Prop() readonly columns: number = 1;
  /** Sets the position of the caret container. This must be a valid CSS position such as '100px'.  */
  @Prop() readonly caretPosition!: string;
  /** Sets the left position of the caret container. This must be a valid CSS position such as '100px'. */
  @Prop() readonly caretPositionLeft: string;
  /** Sets the top position of the sub-menu container. This must be a valid CSS position such as '100px'. */
  @Prop({ mutable: true }) subMenuTopPosition: string;
  /** Sets the bottom position of the sub-menu container. This must be a valid CSS position such as '100px'.*/
  @Prop({ mutable: true }) subMenuBottomPosition: string;
  /** Sets the left position of the sub-menu container. This must be a valid CSS position such as '100px'. */
  @Prop() readonly subMenuLeftPosition: string;

  /** Event emitted when a sub-menu link is clicked. */
  @Event() subMenuLinkClicked: EventEmitter<IVerticalNavItem>;

  private menuColumns: number[] = [];
  private subMenuContainerRef: HTMLDivElement;

  private readonly handleIntersect = (entries: []) => {
    entries.forEach((entry: any) => {
      if (entry.intersectionRatio < 1 && entry.intersectionRatio > 0) {
        if (this.isNotIFrame()) {
          this.subMenuBottomPosition = '0px';
          this.subMenuTopPosition = 'unset';
        }
      }
    });
  };

  private isNotIFrame() {
    return window.location === window.parent.location;
  }

  private readonly observer: IntersectionObserver = new IntersectionObserver(
    this.handleIntersect,
    {
      root: null,
      rootMargin: '0px',
      threshold: [
        0.95, 0.80, 0.65, 0.50,
        0.35, 0.20, 0.15, 0.10, 0.05]
    }
  );

  /** Registers the observer that handles sub-menu intersections (observes). */
  private registerObserver() {
    this.observer.observe(this.subMenuContainerRef);
  }

  /** Disconnects the observer that handles sub-menu intersections (unobserve). */
  private disconnectObserver() {
    this.observer.unobserve(this.subMenuContainerRef);
  }

  componentWillLoad() {
    this.menuColumns = Array.from({ length: this.columns }, (_, i) => i + 1);
  }

  private readonly menuClick = (event: CustomEvent<IVerticalNavItem>) => {
    const subMenuitem: IVerticalNavItem = event.detail;
    if (subMenuitem.clickHandler != null) {
      subMenuitem.clickHandler(subMenuitem);
    }
    this.subMenuLinkClicked.emit(subMenuitem);
  };

  render() {
    return (
      <Host>
        <div style={{ display: this.show ? 'block' : 'none' }}>
          <div
            class='mx-vertical-nav-sub-menu__caret absolute 
            w-12 h-12 bg-primary border-neutral-least-subtle border-l border-t'
            style={{ top: this.caretPosition, left: this.caretPositionLeft || 'unset' }}>
          </div>
          <div
            ref={(ref) => this.subMenuContainerRef = ref}
            class='mx-vertical-nav-sub-menu__container 
            bg-primary align-top rounded-4 border-neutral-least-subtle border'
            style={{
              top: this.subMenuTopPosition,
              bottom: this.subMenuBottomPosition,
              left: this.subMenuLeftPosition
            }}>
            {this.menuColumns.map((x: any) => {
              return (
                <div class='inline-block align-top'>
                  <mx-sub-menu
                    onSubMenuClickHandler={this.menuClick}
                    columnNum={x}
                    columns={this.columns}
                    subMenu={this.data}>
                  </mx-sub-menu>
                </div>
              );
            })}
          </div>
        </div>
      </Host>
    );
  }
}
