/* eslint-disable max-len */
import { Component, Event, EventEmitter, h, Host, Prop, Watch, Element, Listen, Method } from '@stencil/core';
import { isNullOrUndefined } from '@src/utils/mx-utils/utils';
import { IMenuItem } from '@src/mx-components/layout/mx-nav/mx-nav.model';
import { hideAllSubmenus } from '../mx-vertical-nav-sub-menu/mx-vertical-nav-sub-menu-utils';
import { IVerticalNavItem } from '../mx-vertical-nav.interface';
import { computePosition, offset } from '@floating-ui/dom';

@Component({
  tag: 'mx-vertical-nav-item',
  styleUrl: 'mx-vertical-nav-item.css'
})
export class MxVerticalNavItem {

  @Element() hostElement: HTMLMxVerticalNavItemElement;

  /** Sets the item to be displayed. */
  @Prop({ mutable: true }) item!: IVerticalNavItem;
  /** Sets the number of columns. */
  @Prop() readonly columns: number = 1;

  @Watch('item')
  onItemChange(newValue: IVerticalNavItem) {
    if (!isNullOrUndefined(this.subMenuRef)) {
      if (newValue.children != null && newValue.children.length > 0) {
        this.subMenuRef.data = [...(newValue.children.map((ch1) => ch1))];
      }
      const show: boolean = newValue.showSubMenu == undefined ? this.subMenuRef.show : newValue.showSubMenu;
      if (show) {
        this.updatePosition();
      }
      this.subMenuRef.show = show;
    }
    this.checkLabelOverflow();
  }

  /** Event emitted whenever a item is clicked.  */
  @Event() clickHandler: EventEmitter<IVerticalNavItem>;
  /** Event emitted when a sub-menu link is clicked. */
  @Event() subMenuLinkClicked: EventEmitter<IMenuItem[]>;

  private subMenuRef: HTMLMxVerticalNavSubMenuElement;
  private verticalNavContentRef: HTMLElement;
  private labelRef: HTMLSpanElement;

  private hasChildren: boolean;
  private verticalNavPanelIsScrollable = false;
  private hasLabelOverflow = false;
  private readonly REM_VALUE: number = parseFloat(getComputedStyle(document.documentElement).fontSize);

  @Listen('mouseenter')
  onMouseEnter() {
    this.showSubMenu(true);
  }

  // We don't want to hide the sub-menu if the user is trying to navigate towards it.
  // We have a separate eventListener for the sub-menu so that it is hidden when the user's mouse is outside of it.
  @Listen('mouseleave')
  onMouseLeave(event: MouseEvent) {
    if (!this.verticalNavPanelIsScrollable) {
      const relatedTarget = (event.relatedTarget as HTMLElement);
      if (!isNullOrUndefined(relatedTarget) && !isNullOrUndefined(relatedTarget.classList)) {
        const show = relatedTarget.classList.contains('mx-vertical-nav-sub-menu__caret') ||
          relatedTarget.classList.contains('mx-vertical-nav-sub-menu__container');
        if (!show) {
          this.showSubMenu(false);
        }
      } else {
        this.showSubMenu(false);
      }
    }
  }

  componentWillLoad() {
    this.hasChildren = this.item.hasOwnProperty('children') && this.item.children.length > 0;
  }

  componentDidLoad() {
    const verticalNavRoot = document.querySelector('mx-vertical-nav');

    const verticalNavPanelRoot = verticalNavRoot?.shadowRoot?.querySelector('mx-vertical-nav-panel');
    const verticalNavPanel = verticalNavPanelRoot?.shadowRoot?.querySelector('.mx-vertical-nav__panel');
    if (!isNullOrUndefined(verticalNavPanel)) {
      this.verticalNavPanelIsScrollable = verticalNavPanel.scrollHeight > verticalNavPanel.clientHeight;
    }
    // Let's create the sub-menu as soon as we load the component so we don't have to wait for it to be created
    if (this.hasChildren) {
      this.subMenuRef = document.createElement('mx-vertical-nav-sub-menu');
      this.subMenuRef.columns = this.columns;
      this.subMenuRef.data = this.item.children;

      this.subMenuRef.addEventListener('mouseleave', () => {
        this.showSubMenu(false);
      });
      this.subMenuRef.addEventListener('subMenuLinkClicked', (event: CustomEvent<IMenuItem[]>) => {
        this.subMenuLinkClicked.emit(event.detail);
      });

      // Let's assume there will only ever be one vertical nav on the page at once, otherwise we'll have to do something ugly like below:
      // this.hostElement.parentElement.parentElement.parentElement.querySelector('.mx-vertical-nav__content')
      this.verticalNavContentRef = verticalNavPanelRoot?.shadowRoot?.querySelector('.mx-vertical-nav__content');
      if (!isNullOrUndefined(this.verticalNavContentRef)) {
        document.body.appendChild(this.subMenuRef);
      }

      if (this.item.showSubMenu) {
        this.updatePosition();
      }
      this.subMenuRef.show = !!this.item.showSubMenu;
    }
    this.checkLabelOverflow();
  }

  /** Shows or hides the sub menu. */
  @Method()
  async showSubMenu(status: boolean) {
    const { disabled } = this.checkCurrentSelectedDisabledState();
    if (disabled) {
      return;
    }
    // We're deliberately hiding all submenus even if the item doesn't have a submenu because of a trade-off.
    hideAllSubmenus();
    if (!isNullOrUndefined(this.subMenuRef)) {
      if (status) {
        this.updatePosition();
      }
      this.item = { ...this.item, showSubMenu: status };
      this.subMenuRef.show = status;
    }
  }

  private readonly updatePosition = () => {
    computePosition(this.hostElement, this.subMenuRef, {
      placement: 'right-start',
      strategy: 'absolute',
      middleware: [
        offset({ crossAxis: -8 })
      ]
    }).then(({
      x,
      y
    }) => {
      this.subMenuRef.subMenuBottomPosition = 'unset';
      const remY = y / this.REM_VALUE;
      this.subMenuRef.subMenuTopPosition = `${remY}rem`;
      this.subMenuRef.subMenuLeftPosition = `${x / this.REM_VALUE}rem`;
      this.subMenuRef.caretPosition = `${remY + 1.30}rem`;
      this.subMenuRef.caretPositionLeft = `${x / this.REM_VALUE + .15}rem`;
    });
  };

  private checkLabelOverflow() {
    if (!isNullOrUndefined(this.labelRef)) {
      this.hasLabelOverflow = this.labelRef.scrollWidth > this.labelRef.clientWidth;
    }
  }

  private checkCurrentSelectedDisabledState() {
    const selectedChildren: IVerticalNavItem[] = [];
    const disabledChildren: IVerticalNavItem[] = [];
    let childrenCount = 0;

    if (this.hasChildren) {
      this.item.children.forEach((ch1: IVerticalNavItem) => {
        if (ch1.children != null && ch1.children.length > 0) {
          ch1.children.forEach((ch2: IVerticalNavItem) => {
            childrenCount++;
            if (ch2.selected) {
              selectedChildren.push(ch2);
            }
            if (ch2.disabled) {
              disabledChildren.push(ch2);
            }
          });
        } else {
          childrenCount++;
          if (ch1.selected) {
            selectedChildren.push(ch1);
          }
          if (ch1.disabled) {
            disabledChildren.push(ch1);
          }
        }
      });
    }

    const allChildrenDisabled: boolean = childrenCount > 0 && childrenCount === disabledChildren.length;
    const disabled: boolean = this.item.disabled || allChildrenDisabled;
    const selected: boolean = this.item.selected || selectedChildren.length > 0;

    return { disabled, selected };
  }

  render() {
    const noIcon: boolean = isNullOrUndefined(this.item.icon);

    const { disabled, selected } = this.checkCurrentSelectedDisabledState();


    return (
      <Host>
        <li class={{
          'mx-vertical-nav-item text-primary': true,
          'mx-vertical-nav-item_disabled': disabled,
          'mx-vertical-nav-item_selected border-accent-more-prominent': selected
        }}>
          <button
            class={{
              'mx-vertical-nav-item__inner': true,
              'font-base':true,
              'text-tertiary': disabled,
              'mx-vertical-nav-item__inner_no-icon': noIcon
            }}
            disabled={ disabled }
            onClick={() => {
              if (this.item.clickHandler != null) {
                this.item.clickHandler(this.item);
              }
              this.clickHandler.emit(this.item);
            }}>
            <div>
              {!noIcon ?
                <div class='mx-vertical-nav-item__icon'>
                  {
                    this.item.icon === 'mx-mh-icon'?
                      <img
                        src='data:image/svg+xml;base64,'
                        class='mx-merchhub-icon'
                        alt='The Merchhub logo'/> :
                      h(this.item.icon)
                  }
                </div>
                : ''}
              <span
                ref={(el) => this.labelRef = el}
                class='mx-vertical-nav__label'
                title={this.hasLabelOverflow ? this.item.label : undefined}>
                {this.item.label}
              </span>
            </div>
            {
              this.hasChildren ?
                <div class={{
                  'mx-vertical-nav-item__caret text-brand-more-prominent': true,
                  'text-tertiary': disabled,
                  'mx-vertical-nav-item__caret_opened': this.item.showSubMenu
                }}>
                  <kds-icon-chevron-down size='xs' />
                </div> :
                <span />
            }
          </button>
        </li>
      </Host>
    );
  }
}
